 76→    use super::*;
 77→
 78→    #[test]
 79→    fn capability_factory_methods() {
 80→        assert_eq!(Capability::fs_read("/tmp").as_str(), "fs:read:/tmp");
 81→        assert_eq!(Capability::fs_write("/out").as_str(), "fs:write:/out");
 82→        assert_eq!(
 83→            Capability::net_egress("api.com").as_str(),
