 13→#[derive(Debug, Clone, Serialize, Deserialize)]
 14→pub struct SandboxLimits {
 15→    pub max_runtime_secs: u64,
 16→    pub max_output_bytes: usize,
 17→}
 18→
 19→impl Default for SandboxLimits {
 20→    fn default() -> Self {
 21→        Self {
 22→            max_runtime_secs: 30,
 23→            max_output_bytes: 64 * 1024,
 24→        }
 25→    }
 26→}
