 28→#[derive(Debug, Clone, Serialize, Deserialize)]
 29→pub struct SandboxRequest {
 30→    pub command: String,
 31→    pub args: Vec<String>,
 32→    pub cwd: PathBuf,
 33→    pub env: BTreeMap<String, String>,
 34→    pub required_capabilities: Vec<Capability>,
 35→    pub limits: SandboxLimits,
 36→}
 37→
 38→#[derive(Debug, Clone, Serialize, Deserialize)]
 39→pub struct SandboxExecution {
 40→    pub started_at: DateTime<Utc>,
 41→    pub ended_at: DateTime<Utc>,
 42→    pub duration_ms: i64,
 43→    pub exit_code: i32,
 44→    pub stdout: String,
 45→    pub stderr: String,
 46→    pub timed_out: bool,
 47→}
 48→
 49→#[async_trait]
 50→pub trait SandboxRunner: Send + Sync {
 51→    async fn run(&self, request: SandboxRequest) -> Result<SandboxExecution>;
 52→}
 53→
 54→#[derive(Debug, Clone)]
 55→pub struct LocalSandboxRunner {
 56→    pub allowed_commands: Vec<String>,
 57→}
 58→
 59→impl LocalSandboxRunner {
 60→    pub fn new(allowed_commands: Vec<String>) -> Self {
 61→        Self { allowed_commands }
 62→    }
 63→
 64→    fn command_allowed(&self, command: &str) -> bool {
 65→        self.allowed_commands.is_empty() || self.allowed_commands.iter().any(|c| c == command)
 66→    }
 67→
 68→    fn truncate(output: Vec<u8>, max_output_bytes: usize) -> String {
 69→        let mut output = output;
 70→        if output.len() > max_output_bytes {
 71→            output.truncate(max_output_bytes);
 72→        }
 73→        String::from_utf8_lossy(&output).into_owned()
 74→    }
 75→}
 76→
 77→#[async_trait]
 78→impl SandboxRunner for LocalSandboxRunner {
 79→    #[instrument(
 80→        skip(self, request),
 81→        fields(
 82→            command = %request.command,
 83→            args_count = request.args.len(),
 84→            cwd = %request.cwd.display()
 85→        )
 86→    )]
 87→    async fn run(&self, request: SandboxRequest) -> Result<SandboxExecution> {
 88→        if !self.command_allowed(&request.command) {
 89→            bail!("command not allowed in sandbox: {}", request.command);
 90→        }
 91→
 92→        let started_at = Utc::now();
 93→
 94→        let mut command = Command::new(&request.command);
 95→        command.args(&request.args);
 96→        command.current_dir(&request.cwd);
 97→        command.env_clear();
 98→        command.envs(&request.env);
 99→
100→        let output_future = command.output();
101→        let limit = Duration::from_secs(request.limits.max_runtime_secs.max(1));
102→
103→        match timeout(limit, output_future).await {
104→            Ok(output_result) => {
105→                let output = output_result?;
106→                let ended_at = Utc::now();
107→                let stdout = Self::truncate(output.stdout, request.limits.max_output_bytes);
108→                let stderr = Self::truncate(output.stderr, request.limits.max_output_bytes);
109→                let execution = SandboxExecution {
110→                    started_at,
111→                    ended_at,
112→                    duration_ms: (ended_at - started_at).num_milliseconds(),
113→                    exit_code: output.status.code().unwrap_or(-1),
114→                    stdout,
115→                    stderr,
116→                    timed_out: false,
117→                };
118→                debug!(
119→                    exit_code = execution.exit_code,
120→                    duration_ms = execution.duration_ms,
121→                    "sandbox command finished"
122→                );
123→                Ok(execution)
124→            }
125→            Err(_) => {
126→                let ended_at = Utc::now();
127→                warn!(
128→                    max_runtime_secs = request.limits.max_runtime_secs,
129→                    "sandbox command timed out"
130→                );
131→                Ok(SandboxExecution {
132→                    started_at,
133→                    ended_at,
134→                    duration_ms: (ended_at - started_at).num_milliseconds(),
135→                    exit_code: -1,
136→                    stdout: String::new(),
137→                    stderr: format!(
138→                        "sandbox timeout after {} seconds",
139→                        request.limits.max_runtime_secs
140→                    ),
141→                    timed_out: true,
142→                })
143→            }
144→        }
145→    }
146→}
