 26→#[derive(Debug, Clone, Serialize, Deserialize)]
 27→pub struct ToolDefinition {
 28→    pub name: String,
 29→    pub description: String,
 30→    pub required_capabilities: Vec<Capability>,
 31→    pub kind: ToolKind,
 32→}
 33→
 34→#[derive(Debug, Default, Clone)]
 35→pub struct ToolRegistry {
 36→    tools: HashMap<String, ToolDefinition>,
 37→}
 38→
 39→impl ToolRegistry {
 40→    pub fn register(&mut self, definition: ToolDefinition) {
 41→        self.tools.insert(definition.name.clone(), definition);
 42→    }
 43→
 44→    pub fn get(&self, name: &str) -> Option<&ToolDefinition> {
 45→        self.tools.get(name)
 46→    }
 47→
 48→    pub fn definitions(&self) -> impl Iterator<Item = &ToolDefinition> {
 49→        self.tools.values()
 50→    }
 51→
 52→    pub fn with_core_tools() -> Self {
 53→        let mut registry = Self::default();
 54→
 55→        registry.register(ToolDefinition {
 56→            name: "fs.read".to_owned(),
 57→            description: "Read a UTF-8 text file from the session workspace".to_owned(),
 58→            required_capabilities: vec![Capability::fs_read("/session/**")],
 59→            kind: ToolKind::FsRead,
 60→        });
 61→
 62→        registry.register(ToolDefinition {
 63→            name: "fs.write".to_owned(),
 64→            description: "Write a UTF-8 text file to the session workspace".to_owned(),
 65→            required_capabilities: vec![Capability::fs_write("/session/artifacts/**")],
 66→            kind: ToolKind::FsWrite,
 67→        });
 68→
 69→        registry.register(ToolDefinition {
 70→            name: "shell.exec".to_owned(),
 71→            description: "Execute a constrained command through the sandbox runner".to_owned(),
 72→            required_capabilities: vec![Capability::exec("*")],
 73→            kind: ToolKind::ShellExec,
 74→        });
 75→
 76→        registry
 77→    }
 78→}
