 94→#[derive(Debug, Clone, Serialize, Deserialize)]
 95→pub enum DispatchResult {
 96→    Executed(ToolExecutionReport),
 97→    NeedsApproval {
 98→        tool_name: String,
 99→        evaluation: PolicyEvaluation,
100→    },
101→}
102→
103→#[derive(Clone)]
104→pub struct ToolDispatcher {
105→    registry: Arc<ToolRegistry>,
106→    policy: Arc<dyn PolicyEngine>,
107→    sandbox: Arc<dyn SandboxRunner>,
108→}
109→
110→impl ToolDispatcher {
111→    pub fn new(
112→        registry: Arc<ToolRegistry>,
113→        policy: Arc<dyn PolicyEngine>,
114→        sandbox: Arc<dyn SandboxRunner>,
115→    ) -> Self {
116→        Self {
117→            registry,
118→            policy,
119→            sandbox,
120→        }
121→    }
122→
123→    pub fn registry(&self) -> Arc<ToolRegistry> {
124→        self.registry.clone()
125→    }
126→
127→    pub async fn dispatch(
128→        &self,
129→        session_id: SessionId,
130→        context: &ToolContext,
131→        call: ToolCall,
132→    ) -> Result<DispatchResult> {
133→        let span = tracing::info_span!(
134→            "tool.dispatch",
135→            session_id = %session_id,
136→            tool = %call.tool_name,
137→            requested_capabilities = call.requested_capabilities.len()
138→        );
139→        let _enter = span.enter();
140→
141→        let definition = self
142→            .registry
143→            .get(&call.tool_name)
144→            .with_context(|| format!("unknown tool: {}", call.tool_name))?
145→            .clone();
146→
147→        let mut requested_capabilities = definition.required_capabilities.clone();
148→        requested_capabilities.extend(call.requested_capabilities.clone());
149→
150→        let evaluation = self
151→            .policy
152→            .evaluate_capabilities(session_id, &requested_capabilities)
153→            .await;
154→
155→        if !evaluation.denied.is_empty() {
156→            warn!(denied = evaluation.denied.len(), "tool capabilities denied");
157→            bail!("capabilities denied for tool {}", definition.name);
158→        }
159→
160→        if !evaluation.requires_approval.is_empty() {
161→            debug!(
162→                approvals_required = evaluation.requires_approval.len(),
163→                "tool execution requires approval"
164→            );
165→            return Ok(DispatchResult::NeedsApproval {
166→                tool_name: definition.name,
167→                evaluation,
168→            });
169→        }
170→
171→        let tool_run_id = ToolRunId::default();
172→        let (exit_status, outcome) = match definition.kind {
173→            ToolKind::FsRead => self.execute_fs_read(context, &call.input).await?,
174→            ToolKind::FsWrite => self.execute_fs_write(context, &call.input).await?,
175→            ToolKind::ShellExec => self.execute_shell_exec(context, &call).await?,
176→        };
177→        debug!(exit_status, "tool execution finished");
178→
179→        Ok(DispatchResult::Executed(ToolExecutionReport {
180→            tool_run_id,
181→            tool_name: definition.name,
182→            evaluation,
183→            exit_status,
184→            outcome,
185→        }))
186→    }
187→
188→    #[instrument(skip(self, context, input), fields(tool = "fs.read"))]
189→    async fn execute_fs_read(
190→        &self,
191→        context: &ToolContext,
192→        input: &Value,
193→    ) -> Result<(i32, ToolOutcome)> {
194→        let path = input
195→            .get("path")
196→            .and_then(Value::as_str)
197→            .context("fs.read requires input.path")?;
198→        let absolute = canonical_session_path(&context.workspace_root, path)?;
199→        let content = fs::read_to_string(&absolute)
200→            .await
201→            .with_context(|| format!("failed reading file {absolute:?}"))?;
202→        Ok((
203→            0,
204→            ToolOutcome::Success {
205→                output: json!({ "path": path, "content": content }),
206→            },
207→        ))
208→    }
209→
210→    #[instrument(skip(self, context, input), fields(tool = "fs.write"))]
211→    async fn execute_fs_write(
212→        &self,
213→        context: &ToolContext,
214→        input: &Value,
215→    ) -> Result<(i32, ToolOutcome)> {
216→        let path = input
217→            .get("path")
218→            .and_then(Value::as_str)
219→            .context("fs.write requires input.path")?;
220→        let content = input
221→            .get("content")
222→            .and_then(Value::as_str)
223→            .context("fs.write requires input.content")?;
224→        let absolute = canonical_session_path(&context.workspace_root, path)?;
225→        if let Some(parent) = absolute.parent() {
226→            fs::create_dir_all(parent).await?;
227→        }
228→        fs::write(&absolute, content)
229→            .await
230→            .with_context(|| format!("failed writing file {absolute:?}"))?;
231→        Ok((
232→            0,
233→            ToolOutcome::Success {
234→                output: json!({ "path": path, "bytes": content.len() }),
235→            },
236→        ))
237→    }
238→
239→    #[instrument(skip(self, context, call), fields(tool = "shell.exec"))]
240→    async fn execute_shell_exec(
241→        &self,
242→        context: &ToolContext,
243→        call: &ToolCall,
244→    ) -> Result<(i32, ToolOutcome)> {
245→        let command = call
246→            .input
247→            .get("command")
248→            .and_then(Value::as_str)
249→            .context("shell.exec requires input.command")?
250→            .to_owned();
251→
252→        let args = call
253→            .input
254→            .get("args")
255→            .and_then(Value::as_array)
256→            .map(|arr| {
257→                arr.iter()
258→                    .filter_map(|v| v.as_str().map(ToOwned::to_owned))
259→                    .collect::<Vec<_>>()
260→            })
261→            .unwrap_or_default();
262→
263→        let execution = self
264→            .sandbox
265→            .run(SandboxRequest {
266→                command,
267→                args,
268→                cwd: context.workspace_root.clone(),
269→                env: Default::default(),
270→                required_capabilities: call.requested_capabilities.clone(),
271→                limits: SandboxLimits::default(),
272→            })
273→            .await?;
274→
275→        let outcome = if execution.exit_code == 0 {
276→            ToolOutcome::Success {
277→                output: json!({
278→                    "stdout": execution.stdout,
279→                    "stderr": execution.stderr,
280→                    "duration_ms": execution.duration_ms,
281→                    "timed_out": execution.timed_out,
282→                }),
283→            }
284→        } else {
285→            ToolOutcome::Failure {
286→                error: format!(
287→                    "command failed (exit={}): {}",
288→                    execution.exit_code, execution.stderr
289→                ),
290→            }
291→        };
292→
293→        Ok((execution.exit_code, outcome))
294→    }
295→}
296→
297→fn canonical_session_path(root: &Path, relative_path: &str) -> Result<PathBuf> {
298→    let normalized = relative_path.trim_start_matches('/');
299→    let candidate = root.join(normalized);
300→    let root = root.canonicalize().unwrap_or_else(|_| root.to_path_buf());
301→    let parent = candidate.parent().unwrap_or(root.as_path());
302→
303→    if !parent.exists() {
304→        return Ok(candidate);
305→    }
306→
307→    let canonical_parent = parent
308→        .canonicalize()
309→        .with_context(|| format!("failed canonicalizing parent {parent:?}"))?;
310→
311→    if !canonical_parent.starts_with(&root) {
312→        bail!("path escapes workspace root: {relative_path}");
313→    }
314→
315→    Ok(candidate)
316→}
317→
318→fn to_kernel_error(error: anyhow::Error) -> KernelError {
319→    KernelError::Runtime(error.to_string())
320→}
321→
322→#[async_trait]
323→impl ToolHarnessPort for ToolDispatcher {
324→    async fn execute(
325→        &self,
326→        request: ToolExecutionRequest,
327→    ) -> std::result::Result<PortToolExecutionReport, KernelError> {
328→        let context = ToolContext {
329→            workspace_root: PathBuf::from(&request.workspace_root),
330→        };
331→        match self
332→            .dispatch(request.session_id, &context, request.call.clone())
333→            .await
334→            .map_err(to_kernel_error)?
335→        {
336→            DispatchResult::Executed(report) => Ok(PortToolExecutionReport {
337→                tool_run_id: report.tool_run_id,
338→                call_id: request.call.call_id,
339→                tool_name: report.tool_name,
340→                exit_status: report.exit_status,
341→                duration_ms: 0,
342→                outcome: report.outcome,
343→            }),
344→            DispatchResult::NeedsApproval { tool_name, .. } => Err(KernelError::ApprovalRequired(
345→                format!("tool execution requires approval: {tool_name}"),
346→            )),
347→        }
348→    }
349→}
