371→            .input
372→            .get("path")
373→            .and_then(|v| v.as_str())
374→            .map(PathBuf::from)
375→            .unwrap_or_else(|| self.policy.workspace_root.clone());
376→
377→        // Resolve base_dir within workspace
378→        let base_dir = self
379→            .policy
380→            .resolve_existing(Path::new(&base_dir))
381→            .map_err(|e| CoreError::ToolExecution {
382→                tool_name: "glob".to_string(),
383→                message: e.to_string(),
384→            })?;
385→
386→        let full_pattern = base_dir.join(pattern).display().to_string();
387→
388→        let matches: Vec<String> = glob::glob(&full_pattern)
389→            .map_err(|e| CoreError::ToolExecution {
390→                tool_name: "glob".to_string(),
391→                message: format!("Invalid glob pattern: {}", e),
392→            })?
393→            .filter_map(Result::ok)
394→            .filter(|path| {
395→                // Only include paths within the workspace
396→                self.policy.resolve_existing(path).is_ok()
397→            })
398→            .map(|path| {
399→                // Return paths relative to workspace root
400→                path.strip_prefix(&self.policy.workspace_root)
401→                    .map(|p| p.display().to_string())
402→                    .unwrap_or_else(|_| path.display().to_string())
403→            })
404→            .collect();
405→
406→        let count = matches.len();
407→
408→        Ok(ToolResult {
409→            call_id: call.call_id.clone(),
410→            tool_name: call.tool_name.clone(),
411→            output: json!({ "matches": matches, "count": count }),
412→            content: None,
413→            is_error: false,
414→            state_patch: None,
415→        })
416→    }
417→}
