136→impl Tool for EditFileTool {
137→    fn definition(&self) -> ToolDefinition {
138→        ToolDefinition {
139→            name: "edit_file".to_string(),
140→            description: "Edits a file using line tags. Operations: replace_line, insert_after_tag, delete_line.".to_string(),
141→            input_schema: json!({
142→                "type": "object",
143→                "properties": {
144→                    "path": { "type": "string", "description": "Path to the file" },
145→                    "ops": {
146→                        "type": "array",
147→                        "items": {
148→                            "type": "object",
149→                            "oneOf": [
150→                                { "properties": { "op": { "const": "replace_line" }, "tag": { "type": "string" }, "new_text": { "type": "string" } }, "required": ["op", "tag", "new_text"] },
151→                                { "properties": { "op": { "const": "insert_after_tag" }, "tag": { "type": "string" }, "new_text": { "type": "string" } }, "required": ["op", "tag", "new_text"] },
152→                                { "properties": { "op": { "const": "delete_line" }, "tag": { "type": "string" } }, "required": ["op", "tag"] }
153→                            ]
154→                        }
155→                    }
156→                },
157→                "required": ["path", "ops"]
158→            }),
159→            title: Some("Edit File".to_string()),
160→            output_schema: None,
161→            annotations: Some(ToolAnnotations {
162→                destructive: true,
163→                ..Default::default()
164→            }),
165→            category: Some("filesystem".to_string()),
166→            tags: vec!["fs".to_string(), "edit".to_string()],
167→            timeout_secs: Some(30),
168→        }
169→    }
170→
171→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, CoreError> {
172→        let path_str = call
173→            .input
174→            .get("path")
175→            .and_then(|v| v.as_str())
176→            .ok_or_else(|| CoreError::ToolExecution {
177→                tool_name: "edit_file".to_string(),
178→                message: "Missing or invalid 'path' argument".to_string(),
179→            })?;
180→
181→        let ops_value = call
182→            .input
183→            .get("ops")
184→            .ok_or_else(|| CoreError::ToolExecution {
185→                tool_name: "edit_file".to_string(),
186→                message: "Missing 'ops' argument".to_string(),
187→            })?;
188→
189→        let ops: Vec<TaggedEditOp> =
190→            serde_json::from_value(ops_value.clone()).map_err(|e| CoreError::ToolExecution {
191→                tool_name: "edit_file".to_string(),
192→                message: format!("Invalid 'ops' format: {}", e),
193→            })?;
194→
195→        let path = self
196→            .policy
197→            .resolve_for_write(Path::new(path_str))
198→            .map_err(|e| CoreError::ToolExecution {
199→                tool_name: "edit_file".to_string(),
200→                message: e.to_string(),
201→            })?;
202→
203→        // Read current content
204→        let content = fs::read_to_string(&path).map_err(|e| CoreError::ToolExecution {
205→            tool_name: "edit_file".to_string(),
206→            message: format!("Failed to read file: {}", e),
207→        })?;
208→
209→        // Apply edits
210→        let new_content =
211→            apply_tagged_edits(&content, &ops).map_err(|e| CoreError::ToolExecution {
212→                tool_name: "edit_file".to_string(),
213→                message: format!("Edit failed: {}", e),
214→            })?;
215→
216→        // Write back
217→        fs::write(&path, &new_content).map_err(|e| CoreError::ToolExecution {
218→            tool_name: "edit_file".to_string(),
219→            message: format!("Failed to write file: {}", e),
220→        })?;
221→
222→        // Return hashed content of the NEW file
223→        let hashed_content = render_hashed_content(&new_content);
224→
225→        Ok(ToolResult {
226→            call_id: call.call_id.clone(),
227→            tool_name: call.tool_name.clone(),
228→            output: json!({ "success": true, "content": hashed_content, "path": path }),
229→            content: None,
230→            is_error: false,
231→            state_patch: None,
232→        })
233→    }
234→}
