 71→#[derive(Debug, Error)]
 72→pub enum SandboxError {
 73→    #[error("shell execution is disabled by policy")]
 74→    ShellDisabled,
 75→    #[error("command violates sandbox policy: {0}")]
 76→    PolicyViolation(String),
 77→    #[error("command runner failed: {0}")]
 78→    Runner(String),
 79→    #[error("command timed out after {0}ms")]
 80→    Timeout(u64),
