233→impl Tool for BashTool {
234→    fn definition(&self) -> ToolDefinition {
235→        ToolDefinition {
236→            name: "bash".to_string(),
237→            description: "Executes a bash command in the sandbox.".to_string(),
238→            input_schema: json!({
239→                "type": "object",
240→                "properties": {
241→                    "command": { "type": "string", "description": "The command line to execute" },
242→                    "cwd": { "type": "string", "description": "Working directory (optional)" }
243→                },
244→                "required": ["command"]
245→            }),
246→            title: Some("Bash Command".to_string()),
247→            output_schema: None,
248→            annotations: Some(ToolAnnotations {
249→                destructive: true,
250→                open_world: true,
251→                requires_confirmation: true,
252→                ..Default::default()
253→            }),
254→            category: Some("shell".to_string()),
255→            tags: vec!["shell".to_string(), "exec".to_string()],
256→            timeout_secs: Some(60),
257→        }
258→    }
259→
260→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, CoreError> {
261→        let command_line = call
262→            .input
263→            .get("command")
264→            .and_then(|v| v.as_str())
265→            .ok_or_else(|| CoreError::ToolExecution {
266→                tool_name: "bash".to_string(),
267→                message: "Missing 'command' argument".to_string(),
268→            })?;
269→
270→        let cwd = call
271→            .input
272→            .get("cwd")
273→            .and_then(|v| v.as_str())
274→            .map(PathBuf::from);
275→
276→        // Naive parsing of command line - in reality we should use words/shlex
277→        // For "bash" tool, we usually run ["/bin/bash", "-c", command_line]
278→        let request = CommandRequest {
279→            executable: "/bin/bash".to_string(),
280→            args: vec!["-c".to_string(), command_line.to_string()],
281→            cwd,
282→            env: BTreeMap::new(),
283→        };
284→
285→        let result =
286→            self.runner
287→                .run(&self.policy, &request)
288→                .map_err(|e| CoreError::ToolExecution {
289→                    tool_name: "bash".to_string(),
290→                    message: e.to_string(),
291→                })?;
292→
293→        Ok(ToolResult {
294→            call_id: call.call_id.clone(),
295→            tool_name: call.tool_name.clone(),
296→            output: json!({
297→                "exit_code": result.exit_code,
298→                "stdout": result.stdout,
299→                "stderr": result.stderr
300→            }),
301→            content: None,
302→            is_error: false,
303→            state_patch: None,
304→        })
305→    }
306→}
