 18→/// Configuration for connecting to an MCP server.
 19→#[derive(Debug, Clone, Serialize, Deserialize)]
 20→#[serde(deny_unknown_fields)]
 21→pub struct McpServerConfig {
 22→    pub name: String,
 23→    pub transport: McpTransport,
 24→}
