 32→/// Bridge: wraps a single MCP tool into Arcan's Tool trait.
 33→pub struct McpTool {
 34→    definition: ToolDefinition,
 35→    peer: Arc<Peer<RoleClient>>,
 36→    mcp_tool_name: String,
 37→    runtime: Handle,
 38→}
 39→
 40→impl Tool for McpTool {
 41→    fn definition(&self) -> ToolDefinition {
 42→        self.definition.clone()
 43→    }
 44→
 45→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, CoreError> {
 46→        let arguments = call.input.as_object().cloned();
 47→
 48→        let params = CallToolRequestParams {
 49→            meta: None,
 50→            name: Cow::Owned(self.mcp_tool_name.clone()),
 51→            arguments,
 52→            task: None,
 53→        };
 54→
 55→        let peer = self.peer.clone();
 56→        let mcp_result: CallToolResult = self
 57→            .runtime
 58→            .block_on(async move { peer.call_tool(params).await })
 59→            .map_err(|e| CoreError::ToolExecution {
 60→                tool_name: call.tool_name.clone(),
 61→                message: format!("MCP call_tool failed: {}", e),
 62→            })?;
 63→
 64→        // Convert MCP content to Arcan ToolContent
 65→        let content: Vec<ToolContent> = mcp_result
 66→            .content
 67→            .iter()
 68→            .filter_map(|c| match &c.raw {
 69→                RawContent::Text(text) => Some(ToolContent::Text {
 70→                    text: text.text.clone(),
 71→                }),
 72→                RawContent::Image(img) => Some(ToolContent::Image {
 73→                    data: img.data.clone(),
 74→                    mime_type: img.mime_type.clone(),
 75→                }),
 76→                _ => None,
 77→            })
 78→            .collect();
 79→
 80→        // Also build a JSON output for backward compat
 81→        let output = if let Some(structured) = &mcp_result.structured_content {
 82→            structured.clone()
 83→        } else {
 84→            let texts: Vec<String> = mcp_result
 85→                .content
 86→                .iter()
 87→                .filter_map(|c| c.as_text().map(|t| t.text.clone()))
 88→                .collect();
 89→            json!({ "text": texts.join("\n") })
 90→        };
 91→
 92→        Ok(ToolResult {
 93→            call_id: call.call_id.clone(),
 94→            tool_name: call.tool_name.clone(),
 95→            output,
 96→            content: if content.is_empty() {
 97→                None
 98→            } else {
 99→                Some(content)
100→            },
101→            is_error: mcp_result.is_error.unwrap_or(false),
102→            state_patch: None,
103→        })
104→    }
105→}
106→
107→/// Convert an MCP tool definition to Arcan's ToolDefinition.
108→fn mcp_tool_to_arcan(server_name: &str, mcp_tool: &McpToolDef) -> (ToolDefinition, String) {
109→    let mcp_name = mcp_tool.name.to_string();
110→    let arcan_name = format!("mcp_{}_{}", server_name, mcp_name);
111→
112→    let annotations = mcp_tool.annotations.as_ref().map(|ann| ArcanAnnotations {
113→        read_only: ann.read_only_hint.unwrap_or(false),
114→        destructive: ann.destructive_hint.unwrap_or(true),
115→        idempotent: ann.idempotent_hint.unwrap_or(false),
116→        open_world: ann.open_world_hint.unwrap_or(true),
117→        requires_confirmation: false,
118→    });
119→
120→    let input_schema = Value::Object(mcp_tool.input_schema.as_ref().clone());
121→
122→    let output_schema = mcp_tool
123→        .output_schema
124→        .as_ref()
125→        .map(|s| Value::Object(s.as_ref().clone()));
126→
127→    let def = ToolDefinition {
128→        name: arcan_name,
129→        description: mcp_tool.description.as_deref().unwrap_or("").to_string(),
130→        input_schema,
131→        title: mcp_tool
132→            .title
133→            .clone()
134→            .or_else(|| mcp_tool.annotations.as_ref().and_then(|a| a.title.clone())),
135→        output_schema,
136→        annotations,
137→        category: Some("mcp".to_string()),
138→        tags: vec!["mcp".to_string(), server_name.to_string()],
139→        timeout_secs: Some(60),
140→    };
141→
142→    (def, mcp_name)
143→}
