145→/// A connected MCP client holding the running service.
146→pub struct McpConnection {
147→    pub server_name: String,
148→    pub tools: Vec<McpTool>,
149→    _service: Box<dyn std::any::Any + Send>,
150→}
151→
152→/// Connect to an MCP server via stdio and return all its tools as Arcan Tool objects.
153→pub async fn connect_mcp_stdio(config: &McpServerConfig) -> Result<McpConnection, McpError> {
154→    let McpTransport::Stdio {
155→        ref command,
156→        ref args,
157→    } = config.transport;
158→
159→    let mut cmd = Command::new(command);
160→    cmd.args(args);
161→
162→    let transport = TokioChildProcess::new(cmd).map_err(|e| McpError::Connection(e.to_string()))?;
163→
164→    let service = ().serve(transport).await.map_err(|e| McpError::Initialize(e.to_string()))?;
165→
166→    // List tools
167→    let tools_result = service
168→        .list_tools(None)
169→        .await
170→        .map_err(|e| McpError::ListTools(e.to_string()))?;
171→
172→    let runtime = Handle::current();
173→    let peer: Arc<Peer<RoleClient>> = Arc::new(service.peer().clone());
174→
175→    let mcp_tools: Vec<McpTool> = tools_result
176→        .tools
177→        .iter()
178→        .map(|mcp_tool| {
179→            let (definition, mcp_tool_name) = mcp_tool_to_arcan(&config.name, mcp_tool);
180→            McpTool {
181→                definition,
182→                peer: peer.clone(),
183→                mcp_tool_name,
184→                runtime: runtime.clone(),
185→            }
186→        })
187→        .collect();
188→
189→    Ok(McpConnection {
190→        server_name: config.name.clone(),
191→        tools: mcp_tools,
192→        _service: Box::new(service),
193→    })
194→}
