  6→/// Parsed SKILL.md frontmatter.
  7→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
  8→pub struct SkillMetadata {
  9→    pub name: String,
 10→    pub description: String,
 11→    #[serde(default)]
 12→    pub license: Option<String>,
 13→    #[serde(default)]
 14→    pub compatibility: Option<String>,
 15→    #[serde(default)]
 16→    pub tags: Vec<String>,
 17→    #[serde(default)]
 18→    pub allowed_tools: Option<Vec<String>>,
 19→    #[serde(default)]
 20→    pub user_invocable: Option<bool>,
 21→    #[serde(default)]
 22→    pub disable_model_invocation: Option<bool>,
 23→    /// Arbitrary key-value metadata.
 24→    #[serde(default, flatten)]
 25→    pub metadata: BTreeMap<String, serde_yaml::Value>,
 26→}
 27→
 28→/// A loaded skill with its full content.
 29→#[derive(Debug, Clone)]
 30→pub struct LoadedSkill {
 31→    pub meta: SkillMetadata,
 32→    /// Markdown instructions (body after frontmatter).
 33→    pub body: String,
 34→    /// Skill directory (for relative file refs).
 35→    pub root_dir: PathBuf,
 36→}
 37→
 38→/// Skill registry: scans directories, caches metadata, loads on demand.
 39→pub struct SkillRegistry {
 40→    skills: BTreeMap<String, LoadedSkill>,
 41→}
 42→
 43→impl SkillRegistry {
 44→    /// Scan directories for SKILL.md files. Returns a registry of discovered skills.
 45→    pub fn discover(dirs: &[PathBuf]) -> Result<Self, SkillError> {
 46→        let mut skills = BTreeMap::new();
 47→
 48→        for dir in dirs {
 49→            if !dir.exists() {
 50→                continue;
 51→            }
 52→
 53→            for entry in walkdir::WalkDir::new(dir)
 54→                .into_iter()
 55→                .filter_map(Result::ok)
 56→                .filter(|e| e.file_type().is_file())
 57→                .filter(|e| {
 58→                    e.file_name()
 59→                        .to_string_lossy()
 60→                        .eq_ignore_ascii_case("SKILL.md")
 61→                })
 62→            {
 63→                let path = entry.path();
 64→                let content = std::fs::read_to_string(path).map_err(|e| SkillError::Io {
 65→                    path: path.to_path_buf(),
 66→                    source: e,
 67→                })?;
 68→
 69→                match parse_skill_md(&content) {
 70→                    Ok((meta, body)) => {
 71→                        let root_dir = path
 72→                            .parent()
 73→                            .unwrap_or_else(|| Path::new("."))
 74→                            .to_path_buf();
 75→
 76→                        let name = meta.name.clone();
 77→                        skills.insert(
 78→                            name,
 79→                            LoadedSkill {
 80→                                meta,
 81→                                body,
 82→                                root_dir,
 83→                            },
 84→                        );
 85→                    }
 86→                    Err(e) => {
 87→                        // Log but don't fail — skip malformed skills
 88→                        tracing::warn!(
 89→                            path = %path.display(),
 90→                            error = %e,
 91→                            "Skipping malformed skill"
 92→                        );
 93→                    }
 94→                }
 95→            }
 96→        }
 97→
 98→        Ok(Self { skills })
 99→    }
100→
101→    /// Number of discovered skills.
102→    pub fn count(&self) -> usize {
103→        self.skills.len()
104→    }
105→
106→    /// Get skill metadata for system prompt injection.
107→    /// Returns a compact listing of all available skills (~100 tokens per skill).
108→    pub fn system_prompt_catalog(&self) -> String {
109→        if self.skills.is_empty() {
110→            return String::new();
111→        }
112→
113→        let mut lines = vec!["Available skills:".to_string()];
114→        for skill in self.skills.values() {
115→            let invocable = if skill.meta.user_invocable == Some(true) {
116→                " [user-invocable]"
117→            } else {
118→                ""
119→            };
120→            lines.push(format!(
121→                "- {}: {}{}",
122→                skill.meta.name, skill.meta.description, invocable
123→            ));
124→        }
125→        lines.join("\n")
126→    }
127→
128→    /// Load full skill content when activated.
129→    pub fn activate(&self, name: &str) -> Option<&LoadedSkill> {
130→        self.skills.get(name)
131→    }
132→
133→    /// Get all skill names.
134→    pub fn skill_names(&self) -> Vec<String> {
135→        self.skills.keys().cloned().collect()
136→    }
137→
138→    /// Get allowed tools for an active skill (if restricted).
139→    pub fn allowed_tools(&self, name: &str) -> Option<&[String]> {
140→        self.skills
141→            .get(name)
142→            .and_then(|s| s.meta.allowed_tools.as_deref())
143→    }
144→}
145→
146→/// Parse a SKILL.md file into metadata + body.
147→pub fn parse_skill_md(content: &str) -> Result<(SkillMetadata, String), SkillError> {
148→    let trimmed = content.trim();
149→
150→    if !trimmed.starts_with("---") {
151→        return Err(SkillError::MissingFrontmatter);
152→    }
153→
154→    // Find the closing "---" (skip the first one)
155→    let after_first = &trimmed[3..];
156→    let closing = after_first
157→        .find("\n---")
158→        .ok_or(SkillError::MissingFrontmatter)?;
159→
160→    let yaml_str = &after_first[..closing].trim();
161→    let body_start = 3 + closing + 4; // skip "\n---"
162→    let body = if body_start < trimmed.len() {
163→        trimmed[body_start..].trim().to_string()
164→    } else {
165→        String::new()
166→    };
167→
168→    let meta: SkillMetadata =
169→        serde_yaml::from_str(yaml_str).map_err(|e| SkillError::YamlParse(e.to_string()))?;
170→
171→    if meta.name.is_empty() {
172→        return Err(SkillError::MissingField("name".to_string()));
173→    }
174→    if meta.description.is_empty() {
175→        return Err(SkillError::MissingField("description".to_string()));
176→    }
177→
178→    Ok((meta, body))
179→}
180→
181→#[derive(Debug, Error)]
182→pub enum SkillError {
183→    #[error("SKILL.md missing YAML frontmatter (must start and end with ---)")]
184→    MissingFrontmatter,
185→    #[error("YAML parse error: {0}")]
186→    YamlParse(String),
187→    #[error("missing required field: {0}")]
188→    MissingField(String),
189→    #[error("IO error reading {path}: {source}")]
190→    Io {
191→        path: PathBuf,
192→        #[source]
193→        source: std::io::Error,
194→    },
195→}
