  12→/// A shared, swappable provider handle.
  13→///
  14→/// Uses `std::sync::RwLock` (not tokio) because providers use blocking I/O
  15→/// via `spawn_blocking`. Multiple readers can access concurrently; writes
  16→/// only hold the lock for the instant of swapping the inner `Arc`.
  17→pub type SwappableProviderHandle = Arc<std::sync::RwLock<Arc<dyn Provider>>>;
