  19→/// Factory for building providers from a spec string at runtime.
  20→///
  21→/// The spec format is `"provider_name"` or `"provider_name:model"`.
  22→pub trait ProviderFactory: Send + Sync {
  23→    /// Build a new provider from a spec like `"anthropic"` or `"ollama:llama3.2"`.
  24→    fn build(&self, spec: &str) -> Result<Arc<dyn Provider>, CoreError>;
  25→
  26→    /// List the available provider names (e.g. `["anthropic", "openai", "ollama", "mock"]`).
  27→    fn available_providers(&self) -> Vec<String>;
  28→}
