  1→use lago_core::event::PolicyDecisionKind;
  2→use lago_core::policy::{PolicyContext, PolicyDecision};
  3→
  4→use crate::rule::Rule;
  5→
  6→/// Rule-based policy engine that evaluates tool invocations against an ordered
  7→/// set of rules.
  8→pub struct PolicyEngine {
  9→    /// Rules sorted by priority (lower number = higher priority = evaluated first).
 10→    rules: Vec<Rule>,
 11→}
 12→
 13→impl PolicyEngine {
 14→    /// Create a new empty policy engine.
 15→    pub fn new() -> Self {
 16→        Self { rules: Vec::new() }
 17→    }
 18→
 19→    /// Insert a rule, maintaining sort order by priority.
 20→    pub fn add_rule(&mut self, rule: Rule) {
 21→        let pos = self
 22→            .rules
 23→            .binary_search_by_key(&rule.priority, |r| r.priority)
 24→            .unwrap_or_else(|pos| pos);
 25→        self.rules.insert(pos, rule);
 26→    }
 27→
 28→    /// Evaluate the policy context against all rules in priority order.
 29→    /// Returns the decision from the first matching rule.
 30→    /// If no rule matches, defaults to Allow.
 31→    pub fn evaluate(&self, ctx: &PolicyContext) -> PolicyDecision {
 32→        for rule in &self.rules {
 33→            if rule.condition.matches(ctx) {
 34→                return PolicyDecision {
 35→                    decision: rule.decision,
 36→                    rule_id: Some(rule.id.clone()),
 37→                    explanation: rule.explanation.clone(),
 38→                    required_sandbox: rule.required_sandbox,
 39→                };
 40→            }
 41→        }
 42→
 43→        // Default: allow if no rules matched
 44→        PolicyDecision {
 45→            decision: PolicyDecisionKind::Allow,
 46→            rule_id: None,
 47→            explanation: None,
 48→            required_sandbox: None,
 49→        }
 50→    }
 51→
 52→    /// Remove a rule by its ID. Returns `true` if a rule was removed.
 53→    pub fn remove_rule(&mut self, rule_id: &str) -> bool {
 54→        let len_before = self.rules.len();
 55→        self.rules.retain(|r| r.id != rule_id);
 56→        self.rules.len() < len_before
 57→    }
