    #[test]
    fn event_handler_receives_all_events() {
        let provider = ScriptedProvider {
            turns: vec![ModelTurn {
                directives: vec![ModelDirective::FinalAnswer {
                    text: "done".to_string(),
                }],
                stop_reason: ModelStopReason::EndTurn,
                usage: None,
            }],
            cursor: Mutex::new(0),
        };

        let orchestrator = Orchestrator::new(
            Arc::new(provider),
            ToolRegistry::default(),
            Vec::new(),
            OrchestratorConfig {
                max_iterations: 4,
                context: None,
                context_compiler: None,
            },
        );

        let received = Arc::new(Mutex::new(Vec::new()));
        let received_clone = received.clone();

        orchestrator.run(
            RunInput {
                run_id: "run-1".to_string(),
                session_id: "s1".to_string(),
                branch_id: "main".to_string(),
                messages: vec![ChatMessage::user("test")],
                state: AppState::default(),
            },
            move |event| {
                received_clone.lock().unwrap().push(event);
            },
        );

        let events = received.lock().unwrap();
        assert!(events.len() >= 4); // RunStarted, IterationStarted, ModelOutput, TextDelta, RunFinished
        assert!(matches!(events[0], AgentEvent::RunStarted { .. }));
        assert!(matches!(
            events.last().unwrap(),
            AgentEvent::RunFinished { .. }
        ));
    }

