 12→#[derive(Debug, Clone)]
 13→pub struct FsPolicy {
 14→    pub workspace_root: PathBuf,
 15→}
 16→
 17→impl FsPolicy {
 18→    pub fn new(workspace_root: PathBuf) -> Self {
 19→        Self { workspace_root }
 20→    }
 21→
 22→    pub fn resolve_existing(&self, candidate: &Path) -> Result<PathBuf, FsPolicyError> {
 23→        let joined = if candidate.is_absolute() {
 24→            candidate.to_path_buf()
 25→        } else {
 26→            self.workspace_root.join(candidate)
 27→        };
 28→
 29→        let canonical = joined.canonicalize().map_err(|source| FsPolicyError::Io {
 30→            path: joined.clone(),
 31→            source,
 32→        })?;
 33→
 34→        self.ensure_within_root(&canonical)?;
 35→        Ok(canonical)
 36→    }
 37→
 38→    pub fn resolve_for_write(&self, candidate: &Path) -> Result<PathBuf, FsPolicyError> {
 39→        let joined = if candidate.is_absolute() {
 40→            candidate.to_path_buf()
 41→        } else {
 42→            self.workspace_root.join(candidate)
 43→        };
 44→
 45→        // For write, the parent must exist, but the file itself might not.
 46→        let parent = joined
 47→            .parent()
 48→            .ok_or_else(|| FsPolicyError::InvalidPath(joined.display().to_string()))?;
 49→
 50→        // If parent doesn't exist, we can't write there (unless we recursively create, which might be a policy choice).
 51→        // For now let's assume parent must exist or we fail.
 52→        let canonical_parent = parent.canonicalize().map_err(|source| FsPolicyError::Io {
 53→            path: parent.to_path_buf(),
 54→            source,
 55→        })?;
 56→
 57→        self.ensure_within_root(&canonical_parent)?;
 58→
 59→        // Return the path with the canonical parent but the original filename
 60→        Ok(canonical_parent.join(joined.file_name().unwrap()))
 61→    }
 62→
 63→    fn ensure_within_root(&self, candidate: &Path) -> Result<(), FsPolicyError> {
 64→        let root = self
 65→            .workspace_root
 66→            .canonicalize()
 67→            .map_err(|source| FsPolicyError::Io {
 68→                path: self.workspace_root.clone(),
 69→                source,
 70→            })?;
 71→
 72→        if candidate.starts_with(&root) {
 73→            Ok(())
 74→        } else {
 75→            Err(FsPolicyError::EscapesWorkspace {
 76→                path: candidate.display().to_string(),
 77→                root: root.display().to_string(),
 78→            })
 79→        }
 80→    }
 81→}
