 83→#[derive(Debug, Error)]
 84→pub enum FsPolicyError {
 85→    #[error("invalid path: {0}")]
 86→    InvalidPath(String),
 87→    #[error("filesystem IO error on {path}: {source}")]
 88→    Io {
 89→        path: PathBuf,
 90→        #[source]
 91→        source: std::io::Error,
 92→    },
 93→    #[error("path {path} escapes workspace root {root}")]
 94→    EscapesWorkspace { path: String, root: String },
 95→}
