429→impl Tool for GrepTool {
430→    fn definition(&self) -> ToolDefinition {
431→        ToolDefinition {
432→            name: "grep".to_string(),
433→            description: "Search file contents for a regex pattern within the workspace."
434→                .to_string(),
435→            input_schema: json!({
436→                "type": "object",
437→                "properties": {
438→                    "pattern": { "type": "string", "description": "Regex pattern to search for" },
439→                    "path": { "type": "string", "description": "Directory to search (optional, defaults to workspace root)" },
440→                    "glob": { "type": "string", "description": "File glob filter (e.g. *.rs)" },
441→                    "max_matches": { "type": "integer", "description": "Maximum number of matches to return (default 100)" }
442→                },
443→                "required": ["pattern"]
444→            }),
445→            title: Some("Grep Search".to_string()),
446→            output_schema: None,
447→            annotations: Some(ToolAnnotations {
448→                read_only: true,
449→                idempotent: true,
450→                ..Default::default()
451→            }),
452→            category: Some("filesystem".to_string()),
453→            tags: vec!["fs".to_string(), "search".to_string()],
454→            timeout_secs: Some(60),
455→        }
456→    }
457→
458→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, CoreError> {
459→        let pattern_str = call
460→            .input
461→            .get("pattern")
462→            .and_then(|v| v.as_str())
463→            .ok_or_else(|| CoreError::ToolExecution {
464→                tool_name: "grep".to_string(),
465→                message: "Missing or invalid 'pattern' argument".to_string(),
466→            })?;
467→
468→        let regex = Regex::new(pattern_str).map_err(|e| CoreError::ToolExecution {
469→            tool_name: "grep".to_string(),
470→            message: format!("Invalid regex pattern: {}", e),
471→        })?;
472→
473→        let base_dir = call
474→            .input
475→            .get("path")
476→            .and_then(|v| v.as_str())
477→            .map(PathBuf::from)
478→            .unwrap_or_else(|| self.policy.workspace_root.clone());
479→
480→        let base_dir = self
481→            .policy
482→            .resolve_existing(Path::new(&base_dir))
483→            .map_err(|e| CoreError::ToolExecution {
484→                tool_name: "grep".to_string(),
485→                message: e.to_string(),
486→            })?;
487→
488→        let glob_filter = call.input.get("glob").and_then(|v| v.as_str());
489→
490→        let max_matches = call
491→            .input
492→            .get("max_matches")
493→            .and_then(serde_json::Value::as_u64)
494→            .unwrap_or(100) as usize;
495→
496→        let mut matches = Vec::new();
497→
498→        for entry in walkdir::WalkDir::new(&base_dir)
499→            .into_iter()
500→            .filter_map(Result::ok)
501→            .filter(|e| e.file_type().is_file())
502→        {
503→            let path = entry.path();
504→
505→            // Apply glob filter if specified
506→            if let Some(glob_pat) = glob_filter {
507→                let file_name = path.file_name().unwrap_or_default().to_string_lossy();
508→                let glob_pattern =
509→                    glob::Pattern::new(glob_pat).map_err(|e| CoreError::ToolExecution {
510→                        tool_name: "grep".to_string(),
511→                        message: format!("Invalid glob filter: {}", e),
512→                    })?;
513→                if !glob_pattern.matches(&file_name) {
514→                    continue;
515→                }
516→            }
517→
518→            // Skip binary files and large files
519→            if let Ok(metadata) = path.metadata() {
520→                if metadata.len() > 10 * 1024 * 1024 {
521→                    continue; // Skip files > 10MB
522→                }
523→            }
524→
525→            let Ok(file) = fs::File::open(path) else {
526→                continue;
527→            };
528→
529→            let reader = BufReader::new(file);
530→            for (line_no, line) in reader.lines().enumerate() {
531→                let Ok(line) = line else {
532→                    continue; // Skip binary/unreadable lines
533→                };
534→
535→                if regex.is_match(&line) {
536→                    let rel_path = path
537→                        .strip_prefix(&self.policy.workspace_root)
538→                        .map(|p| p.display().to_string())
539→                        .unwrap_or_else(|_| path.display().to_string());
540→
541→                    matches.push(json!({
542→                        "file": rel_path,
543→                        "line": line_no + 1,
544→                        "text": line
545→                    }));
546→
547→                    if matches.len() >= max_matches {
548→                        break;
549→                    }
550→                }
551→            }
552→
553→            if matches.len() >= max_matches {
554→                break;
555→            }
556→        }
557→
558→        let count = matches.len();
559→
560→        Ok(ToolResult {
561→            call_id: call.call_id.clone(),
562→            tool_name: call.tool_name.clone(),
563→            output: json!({ "matches": matches, "count": count }),
564→            content: None,
565→            is_error: false,
566→            state_patch: None,
567→        })
568→    }
569→}
