 18→impl Tool for ReadMemoryTool {
 19→    fn definition(&self) -> ToolDefinition {
 20→        ToolDefinition {
 21→            name: "read_memory".to_string(),
 22→            description: "Read the agent's persistent memory file by key.".to_string(),
 23→            input_schema: json!({
 24→                "type": "object",
 25→                "properties": {
 26→                    "key": { "type": "string", "description": "Memory key (e.g. 'global', 'session', or custom name)" }
 27→                },
 28→                "required": ["key"]
 29→            }),
 30→            title: Some("Read Memory".to_string()),
 31→            output_schema: None,
 32→            annotations: Some(ToolAnnotations {
 33→                read_only: true,
 34→                idempotent: true,
 35→                ..Default::default()
 36→            }),
 37→            category: Some("memory".to_string()),
 38→            tags: vec!["memory".to_string(), "read".to_string()],
 39→            timeout_secs: Some(10),
 40→        }
 41→    }
 42→
 43→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, CoreError> {
 44→        let key = call
 45→            .input
 46→            .get("key")
 47→            .and_then(|v| v.as_str())
 48→            .ok_or_else(|| CoreError::ToolExecution {
 49→                tool_name: "read_memory".to_string(),
 50→                message: "Missing or invalid 'key' argument".to_string(),
 51→            })?;
 52→
 53→        validate_memory_key(key).map_err(|msg| CoreError::ToolExecution {
 54→            tool_name: "read_memory".to_string(),
 55→            message: msg,
 56→        })?;
 57→
 58→        let file_path = self.memory_dir.join(format!("{}.md", key));
 59→
 60→        if file_path.exists() {
 61→            let content = fs::read_to_string(&file_path).map_err(|e| CoreError::ToolExecution {
 62→                tool_name: "read_memory".to_string(),
 63→                message: format!("Failed to read memory file: {}", e),
 64→            })?;
 65→
 66→            Ok(ToolResult {
 67→                call_id: call.call_id.clone(),
 68→                tool_name: call.tool_name.clone(),
 69→                output: json!({ "content": content, "exists": true, "path": file_path }),
 70→                content: None,
 71→                is_error: false,
 72→                state_patch: None,
 73→            })
 74→        } else {
 75→            Ok(ToolResult {
 76→                call_id: call.call_id.clone(),
 77→                tool_name: call.tool_name.clone(),
 78→                output: json!({ "content": null, "exists": false, "path": file_path }),
 79→                content: None,
 80→                is_error: false,
 81→                state_patch: None,
 82→            })
 83→        }
 84→    }
