 97→impl Tool for WriteMemoryTool {
 98→    fn definition(&self) -> ToolDefinition {
 99→        ToolDefinition {
100→            name: "write_memory".to_string(),
101→            description: "Write to the agent's persistent memory file by key.".to_string(),
102→            input_schema: json!({
103→                "type": "object",
104→                "properties": {
105→                    "key": { "type": "string", "description": "Memory key (e.g. 'global', 'session', or custom name)" },
106→                    "content": { "type": "string", "description": "Markdown content to write" }
107→                },
108→                "required": ["key", "content"]
109→            }),
110→            title: Some("Write Memory".to_string()),
111→            output_schema: None,
112→            annotations: Some(ToolAnnotations {
113→                destructive: true,
114→                ..Default::default()
115→            }),
116→            category: Some("memory".to_string()),
117→            tags: vec!["memory".to_string(), "write".to_string()],
118→            timeout_secs: Some(10),
119→        }
120→    }
121→
122→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, CoreError> {
123→        let key = call
124→            .input
125→            .get("key")
126→            .and_then(|v| v.as_str())
127→            .ok_or_else(|| CoreError::ToolExecution {
128→                tool_name: "write_memory".to_string(),
129→                message: "Missing or invalid 'key' argument".to_string(),
130→            })?;
131→
132→        let content = call
133→            .input
134→            .get("content")
135→            .and_then(|v| v.as_str())
136→            .ok_or_else(|| CoreError::ToolExecution {
137→                tool_name: "write_memory".to_string(),
138→                message: "Missing or invalid 'content' argument".to_string(),
139→            })?;
140→
141→        validate_memory_key(key).map_err(|msg| CoreError::ToolExecution {
142→            tool_name: "write_memory".to_string(),
143→            message: msg,
144→        })?;
145→
146→        // Ensure memory directory exists
147→        fs::create_dir_all(&self.memory_dir).map_err(|e| CoreError::ToolExecution {
148→            tool_name: "write_memory".to_string(),
149→            message: format!("Failed to create memory directory: {}", e),
150→        })?;
151→
152→        let file_path = self.memory_dir.join(format!("{}.md", key));
153→
154→        fs::write(&file_path, content).map_err(|e| CoreError::ToolExecution {
155→            tool_name: "write_memory".to_string(),
156→            message: format!("Failed to write memory file: {}", e),
157→        })?;
158→
159→        Ok(ToolResult {
160→            call_id: call.call_id.clone(),
161→            tool_name: call.tool_name.clone(),
162→            output: json!({ "success": true, "path": file_path }),
163→            content: None,
164→            is_error: false,
165→            state_patch: None,
166→        })
167→    }
168→}
