170→/// Validate that a memory key is safe (alphanumeric, hyphens, underscores).
171→fn validate_memory_key(key: &str) -> Result<(), String> {
172→    if key.is_empty() {
173→        return Err("Memory key cannot be empty".to_string());
174→    }
175→    if key.len() > 64 {
176→        return Err("Memory key too long (max 64 characters)".to_string());
177→    }
178→    if !key
179→        .chars()
180→        .all(|c| c.is_alphanumeric() || c == '-' || c == '_')
181→    {
182→        return Err(
183→            "Memory key must contain only alphanumeric characters, hyphens, and underscores"
184→                .to_string(),
185→        );
186→    }
187→    if key.starts_with('.') || key.contains("..") {
188→        return Err("Memory key cannot start with '.' or contain '..'".to_string());
189→    }
190→    Ok(())
191→}
