  1→use blake3::Hasher;
  2→use schemars::JsonSchema;
  3→use serde::{Deserialize, Serialize};
  4→use thiserror::Error;
  5→
  6→use crate::fs::FsPolicy;
  7→use arcan_core::error::CoreError;
  8→use arcan_core::protocol::{ToolAnnotations, ToolCall, ToolDefinition, ToolResult};
  9→use arcan_core::runtime::{Tool, ToolContext};
 10→use serde_json::json;
 11→use std::fs;
 12→use std::path::Path;
 13→
 14→#[derive(Debug, Clone, Serialize, Deserialize, JsonSchema, PartialEq, Eq)]
 15→pub struct HashedLine {
 16→    pub line_no: usize,
 17→    pub tag: String,
 18→    pub text: String,
 19→}
 20→
 21→#[derive(Debug, Clone, Serialize, Deserialize, JsonSchema, PartialEq, Eq)]
 22→#[serde(tag = "op", rename_all = "snake_case")]
 23→pub enum TaggedEditOp {
 24→    ReplaceLine { tag: String, new_text: String },
 25→    InsertAfterTag { tag: String, new_text: String },
 26→    DeleteLine { tag: String },
 27→}
 28→
 29→#[derive(Debug, Clone)]
 30→struct EditableLine {
 31→    anchor_tag: Option<String>,
 32→    text: String,
 33→}
 34→
 35→pub fn hash_lines(content: &str) -> Vec<HashedLine> {
 36→    content
 37→        .lines()
 38→        .enumerate()
 39→        .map(|(idx, line)| HashedLine {
 40→            line_no: idx + 1,
 41→            tag: line_tag(idx + 1, line),
 42→            text: line.to_string(),
 43→        })
 44→        .collect()
 45→}
 46→
 47→pub fn render_hashed_content(content: &str) -> String {
 48→    hash_lines(content)
 49→        .into_iter()
 50→        .map(|line| format!("{:>4} {} | {}", line.line_no, line.tag, line.text))
 51→        .collect::<Vec<_>>()
 52→        .join("\n")
 53→}
 54→
 55→pub fn apply_tagged_edits(content: &str, ops: &[TaggedEditOp]) -> Result<String, EditError> {
 56→    let initial_lines = hash_lines(content);
 57→
 58→    if initial_lines.is_empty() && !ops.is_empty() {
 59→        return Err(EditError::EmptyContent);
 60→    }
 61→
 62→    let mut editable = initial_lines
 63→        .iter()
 64→        .map(|line| EditableLine {
 65→            anchor_tag: Some(line.tag.clone()),
 66→            text: line.text.clone(),
 67→        })
 68→        .collect::<Vec<_>>();
 69→
 70→    for op in ops {
 71→        match op {
 72→            TaggedEditOp::ReplaceLine { tag, new_text } => {
 73→                let idx = find_anchor_index(&editable, tag)?;
 74→                editable[idx].text = new_text.clone();
 75→            }
 76→            TaggedEditOp::InsertAfterTag { tag, new_text } => {
 77→                let idx = find_anchor_index(&editable, tag)?;
 78→                editable.insert(
 79→                    idx + 1,
 80→                    EditableLine {
 81→                        anchor_tag: None,
 82→                        text: new_text.clone(),
 83→                    },
 84→                );
 85→            }
 86→            TaggedEditOp::DeleteLine { tag } => {
 87→                let idx = find_anchor_index(&editable, tag)?;
 88→                editable.remove(idx);
 89→            }
 90→        }
 91→    }
 92→
 93→    Ok(editable
