                    "---\nname: {}\ndescription: Skill {}\n---\nBody.",
                    name, name
                ),
            )
            .unwrap();
        }

        let registry = SkillRegistry::discover(&[dir.path().to_path_buf()]).unwrap();
        let mut names = registry.skill_names();
        names.sort();
        assert_eq!(names, vec!["aaa", "bbb", "ccc"]);
    }
}

