 85→pub struct LocalCommandRunner;
 86→
 87→impl LocalCommandRunner {
 88→    /// Validate that a cwd path is within the workspace root.
 89→    fn validate_cwd(
 90→        policy: &SandboxPolicy,
 91→        cwd: &std::path::Path,
 92→    ) -> Result<PathBuf, SandboxError> {
 93→        let resolved = if cwd.is_absolute() {
 94→            cwd.to_path_buf()
 95→        } else {
 96→            policy.workspace_root.join(cwd)
 97→        };
 98→
 99→        // Canonicalize both to resolve symlinks
100→        let canonical = resolved.canonicalize().map_err(SandboxError::Io)?;
101→        let root = policy
102→            .workspace_root
103→            .canonicalize()
104→            .map_err(SandboxError::Io)?;
105→
106→        if canonical.starts_with(&root) {
107→            Ok(canonical)
108→        } else {
109→            Err(SandboxError::PolicyViolation(format!(
110→                "cwd '{}' escapes workspace root '{}'",
111→                canonical.display(),
112→                root.display()
113→            )))
114→        }
115→    }
116→
117→    /// Truncate a byte vector to the given limit, appending a marker if truncated.
118→    fn truncate_output(raw: &[u8], max_bytes: usize) -> String {
119→        if raw.len() <= max_bytes {
120→            String::from_utf8_lossy(raw).to_string()
121→        } else {
122→            let truncated = String::from_utf8_lossy(&raw[..max_bytes]).to_string();
123→            format!(
124→                "{}\n\n... [truncated: {} bytes total, showing first {}]",
125→                truncated,
126→                raw.len(),
127→                max_bytes
128→            )
129→        }
130→    }
131→}
