133→impl CommandRunner for LocalCommandRunner {
134→    fn run(
135→        &self,
136→        policy: &SandboxPolicy,
137→        request: &CommandRequest,
138→    ) -> Result<CommandResult, SandboxError> {
139→        if !policy.shell_enabled {
140→            return Err(SandboxError::ShellDisabled);
141→        }
142→
143→        // 1. Prepare command
144→        let mut cmd = std::process::Command::new(&request.executable);
145→        cmd.args(&request.args);
146→
147→        // 2. Validate and set cwd (enforces workspace boundary)
148→        if let Some(cwd) = &request.cwd {
149→            let validated_cwd = Self::validate_cwd(policy, cwd)?;
150→            cmd.current_dir(validated_cwd);
151→        } else {
152→            cmd.current_dir(&policy.workspace_root);
153→        }
154→
155→        // 3. Environment: clear everything, then allow only explicitly permitted vars.
156→        //    An empty allowed_env set means NO request env vars are passed through.
157→        cmd.env_clear();
158→        for (k, v) in &request.env {
159→            if policy.allowed_env.contains(k) {
160→                cmd.env(k, v);
161→            }
162→        }
163→        // Always provide basic env for shell functionality
164→        cmd.env("PATH", std::env::var("PATH").unwrap_or_default());
165→        cmd.env("TERM", "xterm-256color");
166→
167→        // 4. Spawn child process (not .output() — we need timeout control)
168→        cmd.stdout(std::process::Stdio::piped());
169→        cmd.stderr(std::process::Stdio::piped());
170→        let mut child = cmd.spawn().map_err(SandboxError::Io)?;
171→
172→        // 5. Enforce execution timeout
173→        let timeout = Duration::from_millis(policy.max_execution_ms);
174→        match child.wait_timeout(timeout) {
175→            Ok(Some(status)) => {
176→                // Process exited within timeout — read output
177→                let stdout_raw = child
178→                    .stdout
179→                    .take()
180→                    .map(|mut r| {
181→                        let mut buf = Vec::new();
182→                        std::io::Read::read_to_end(&mut r, &mut buf).unwrap_or(0);
183→                        buf
184→                    })
185→                    .unwrap_or_default();
186→                let stderr_raw = child
187→                    .stderr
188→                    .take()
189→                    .map(|mut r| {
190→                        let mut buf = Vec::new();
191→                        std::io::Read::read_to_end(&mut r, &mut buf).unwrap_or(0);
192→                        buf
193→                    })
194→                    .unwrap_or_default();
195→
196→                // 6. Enforce output size limits
197→                let stdout = Self::truncate_output(&stdout_raw, policy.max_stdout_bytes);
198→                let stderr = Self::truncate_output(&stderr_raw, policy.max_stderr_bytes);
199→
200→                Ok(CommandResult {
201→                    exit_code: status.code().unwrap_or(-1),
202→                    stdout,
203→                    stderr,
204→                })
205→            }
206→            Ok(None) => {
207→                // Timeout expired — kill the process
208→                let _ = child.kill();
209→                let _ = child.wait(); // reap zombie
210→                Err(SandboxError::Timeout(policy.max_execution_ms))
211→            }
212→            Err(e) => Err(SandboxError::Io(e)),
213→        }
214→    }
215→}
