146→/// Parse a SKILL.md file into metadata + body.
147→pub fn parse_skill_md(content: &str) -> Result<(SkillMetadata, String), SkillError> {
148→    let trimmed = content.trim();
149→
150→    if !trimmed.starts_with("---") {
151→        return Err(SkillError::MissingFrontmatter);
152→    }
153→
154→    // Find the closing "---" (skip the first one)
155→    let after_first = &trimmed[3..];
156→    let closing = after_first
157→        .find("\n---")
158→        .ok_or(SkillError::MissingFrontmatter)?;
159→
160→    let yaml_str = &after_first[..closing].trim();
161→    let body_start = 3 + closing + 4; // skip "\n---"
162→    let body = if body_start < trimmed.len() {
163→        trimmed[body_start..].trim().to_string()
164→    } else {
165→        String::new()
166→    };
167→
168→    let meta: SkillMetadata =
169→        serde_yaml::from_str(yaml_str).map_err(|e| SkillError::YamlParse(e.to_string()))?;
170→
171→    if meta.name.is_empty() {
172→        return Err(SkillError::MissingField("name".to_string()));
173→    }
174→    if meta.description.is_empty() {
175→        return Err(SkillError::MissingField("description".to_string()));
176→    }
177→
178→    Ok((meta, body))
179→}
