        assert!(result.is_err());
    }
}

//! Agent memory tools (file-based read/write).
//!
//! Memory is stored as markdown files keyed by name within
//! a configured memory directory.

use aios_protocol::tool::{
    Tool, ToolAnnotations, ToolCall, ToolContext, ToolDefinition, ToolError, ToolResult,
};
use serde_json::json;
use std::fs;
use std::path::PathBuf;

// ── ReadMemoryTool ───────────────────────────────────────────────────

/// Reads the agent's persistent memory file by key.
pub struct ReadMemoryTool {
    memory_dir: PathBuf,
}

impl ReadMemoryTool {
    pub fn new(memory_dir: PathBuf) -> Self {
        Self { memory_dir }
    }
}

impl Tool for ReadMemoryTool {
    fn definition(&self) -> ToolDefinition {
        ToolDefinition {
            name: "read_memory".into(),
            description: "Read the agent's persistent memory file by key.".into(),
            input_schema: json!({
                "type": "object",
                "properties": {
                    "key": { "type": "string", "description": "Memory key (e.g. 'global', 'session', or custom name)" }
                },
                "required": ["key"]
            }),
            title: Some("Read Memory".into()),
            output_schema: None,
            annotations: Some(ToolAnnotations {
                read_only: true,
                idempotent: true,
                ..Default::default()
            }),
            category: Some("memory".into()),
            tags: vec!["memory".into(), "read".into()],
            timeout_secs: Some(10),
        }
    }

    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, ToolError> {
        let key = call
            .input
            .get("key")
            .and_then(|v| v.as_str())
            .ok_or_else(|| ToolError::InvalidInput {
                message: "Missing or invalid 'key' argument".into(),
            })?;

        validate_memory_key(key).map_err(|msg| ToolError::InvalidInput { message: msg })?;

        let file_path = self.memory_dir.join(format!("{key}.md"));

        if file_path.exists() {
            let content =
                fs::read_to_string(&file_path).map_err(|e| ToolError::ExecutionFailed {
                    tool_name: "read_memory".into(),
                    message: format!("Failed to read memory file: {e}"),
                })?;

            Ok(ToolResult {
                call_id: call.call_id.clone(),
                tool_name: call.tool_name.clone(),
                output: json!({ "content": content, "exists": true, "path": file_path }),
                content: None,
                is_error: false,
            })
        } else {
            Ok(ToolResult {
                call_id: call.call_id.clone(),
                tool_name: call.tool_name.clone(),
                output: json!({ "content": null, "exists": false, "path": file_path }),
                content: None,
                is_error: false,
            })
        }
    }
}

// ── WriteMemoryTool ──────────────────────────────────────────────────

/// Writes to the agent's persistent memory file by key.
pub struct WriteMemoryTool {
    memory_dir: PathBuf,
}

impl WriteMemoryTool {
    pub fn new(memory_dir: PathBuf) -> Self {
        Self { memory_dir }
    }
}

impl Tool for WriteMemoryTool {
    fn definition(&self) -> ToolDefinition {
        ToolDefinition {
            name: "write_memory".into(),
            description: "Write to the agent's persistent memory file by key.".into(),
            input_schema: json!({
                "type": "object",
                "properties": {
                    "key": { "type": "string", "description": "Memory key (e.g. 'global', 'session', or custom name)" },
                    "content": { "type": "string", "description": "Markdown content to write" }
                },
                "required": ["key", "content"]
            }),
            title: Some("Write Memory".into()),
            output_schema: None,
            annotations: Some(ToolAnnotations {
                destructive: true,
                ..Default::default()
            }),
            category: Some("memory".into()),
            tags: vec!["memory".into(), "write".into()],
            timeout_secs: Some(10),
        }
    }

    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, ToolError> {
        let key = call
            .input
            .get("key")
            .and_then(|v| v.as_str())
            .ok_or_else(|| ToolError::InvalidInput {
                message: "Missing or invalid 'key' argument".into(),
            })?;

        let content = call
            .input
            .get("content")
            .and_then(|v| v.as_str())
            .ok_or_else(|| ToolError::InvalidInput {
                message: "Missing or invalid 'content' argument".into(),
            })?;

        validate_memory_key(key).map_err(|msg| ToolError::InvalidInput { message: msg })?;

        fs::create_dir_all(&self.memory_dir).map_err(|e| ToolError::ExecutionFailed {
            tool_name: "write_memory".into(),
            message: format!("Failed to create memory directory: {e}"),
        })?;

        let file_path = self.memory_dir.join(format!("{key}.md"));

        fs::write(&file_path, content).map_err(|e| ToolError::ExecutionFailed {
            tool_name: "write_memory".into(),
            message: format!("Failed to write memory file: {e}"),
        })?;

        Ok(ToolResult {
            call_id: call.call_id.clone(),
            tool_name: call.tool_name.clone(),
            output: json!({ "success": true, "path": file_path }),
            content: None,
            is_error: false,
        })
    }
}

/// Validate that a memory key is safe (alphanumeric, hyphens, underscores).
pub fn validate_memory_key(key: &str) -> Result<(), String> {
    if key.is_empty() {
        return Err("Memory key cannot be empty".into());
    }
    if key.len() > 64 {
        return Err("Memory key too long (max 64 characters)".into());
    }
    if !key
        .chars()
        .all(|c| c.is_alphanumeric() || c == '-' || c == '_')
    {
        return Err(
            "Memory key must contain only alphanumeric characters, hyphens, and underscores".into(),
        );
    }
    if key.starts_with('.') || key.contains("..") {
        return Err("Memory key cannot start with '.' or contain '..'".into());
    }
    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;
    use aios_protocol::tool::{ToolCall, ToolContext};
    use tempfile::TempDir;

    fn make_ctx() -> ToolContext {
        ToolContext {
            run_id: "test-run".into(),
            session_id: "test".into(),
            iteration: 0,
        }
    }

    fn make_call(name: &str, input: serde_json::Value) -> ToolCall {
        ToolCall {
            call_id: "test-call".into(),
            tool_name: name.into(),
            input,
        }
    }

    #[test]
    fn write_then_read_memory() {
        let dir = TempDir::new().unwrap();
        let write_tool = WriteMemoryTool::new(dir.path().to_path_buf());
        let read_tool = ReadMemoryTool::new(dir.path().to_path_buf());
        let ctx = make_ctx();

        let call = make_call(
            "write_memory",
            json!({"key": "test-notes", "content": "# Notes\nSome important info."}),
        );
        let result = write_tool.execute(&call, &ctx).unwrap();
        assert_eq!(result.output["success"], true);

        let call = make_call("read_memory", json!({"key": "test-notes"}));
        let result = read_tool.execute(&call, &ctx).unwrap();
        assert_eq!(result.output["exists"], true);
        assert_eq!(result.output["content"], "# Notes\nSome important info.");
    }

    #[test]
    fn read_nonexistent_memory() {
        let dir = TempDir::new().unwrap();
        let read_tool = ReadMemoryTool::new(dir.path().to_path_buf());
        let ctx = make_ctx();

        let call = make_call("read_memory", json!({"key": "nonexistent"}));
        let result = read_tool.execute(&call, &ctx).unwrap();
        assert_eq!(result.output["exists"], false);
        assert!(result.output["content"].is_null());
    }

    #[test]
    fn invalid_memory_key_rejected() {
        assert!(validate_memory_key("").is_err());
        assert!(validate_memory_key("../escape").is_err());
        assert!(validate_memory_key(".hidden").is_err());
        assert!(validate_memory_key("has spaces").is_err());
        assert!(validate_memory_key("has/slash").is_err());

        assert!(validate_memory_key("valid-key").is_ok());
        assert!(validate_memory_key("valid_key").is_ok());
        assert!(validate_memory_key("key123").is_ok());
    }

    #[test]
    fn write_creates_directory() {
        let dir = TempDir::new().unwrap();
        let memory_dir = dir.path().join("memory");
        assert!(!memory_dir.exists());

        let write_tool = WriteMemoryTool::new(memory_dir.clone());
        let ctx = make_ctx();

        let call = make_call(
            "write_memory",
            json!({"key": "auto-created", "content": "hello"}),
        );
        let result = write_tool.execute(&call, &ctx).unwrap();
        assert_eq!(result.output["success"], true);
        assert!(memory_dir.exists());
    }

    #[test]
    fn overwrite_memory() {
        let dir = TempDir::new().unwrap();
        let write_tool = WriteMemoryTool::new(dir.path().to_path_buf());
        let read_tool = ReadMemoryTool::new(dir.path().to_path_buf());
        let ctx = make_ctx();

        let call = make_call(
            "write_memory",
            json!({"key": "overwrite-test", "content": "version 1"}),
        );
        write_tool.execute(&call, &ctx).unwrap();

        let call = make_call(
            "write_memory",
            json!({"key": "overwrite-test", "content": "version 2"}),
        );
        write_tool.execute(&call, &ctx).unwrap();

        let call = make_call("read_memory", json!({"key": "overwrite-test"}));
        let result = read_tool.execute(&call, &ctx).unwrap();
        assert_eq!(result.output["content"], "version 2");
    }
}

//! SKILL.md frontmatter parser.
//!
//! Parses YAML frontmatter from SKILL.md files into [`SkillMetadata`].

use serde::{Deserialize, Serialize};
use std::collections::BTreeMap;
use thiserror::Error;

/// Parsed SKILL.md frontmatter.
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
pub struct SkillMetadata {
    pub name: String,
    pub description: String,
    #[serde(default)]
    pub license: Option<String>,
    #[serde(default)]
    pub compatibility: Option<String>,
    #[serde(default)]
    pub tags: Vec<String>,
    #[serde(default)]
    pub allowed_tools: Option<Vec<String>>,
    #[serde(default)]
    pub user_invocable: Option<bool>,
    #[serde(default)]
    pub disable_model_invocation: Option<bool>,
    /// Arbitrary key-value metadata.
    #[serde(default, flatten)]
    pub metadata: BTreeMap<String, serde_yaml::Value>,
}

/// Parse a SKILL.md file into metadata + body.
pub fn parse_skill_md(content: &str) -> Result<(SkillMetadata, String), SkillParseError> {
    let trimmed = content.trim();

    if !trimmed.starts_with("---") {
        return Err(SkillParseError::MissingFrontmatter);
    }

    // Find the closing "---" (skip the first one)
    let after_first = &trimmed[3..];
    let closing = after_first
        .find("\n---")
        .ok_or(SkillParseError::MissingFrontmatter)?;

    let yaml_str = after_first[..closing].trim();
    let body_start = 3 + closing + 4; // skip "\n---"
    let body = if body_start < trimmed.len() {
        trimmed[body_start..].trim().to_string()
    } else {
        String::new()
    };

    let meta: SkillMetadata =
        serde_yaml::from_str(yaml_str).map_err(|e| SkillParseError::YamlParse(e.to_string()))?;

    if meta.name.is_empty() {
        return Err(SkillParseError::MissingField("name".into()));
    }
    if meta.description.is_empty() {
        return Err(SkillParseError::MissingField("description".into()));
    }

    Ok((meta, body))
}

/// Errors from SKILL.md parsing.
#[derive(Debug, Error)]
pub enum SkillParseError {
    #[error("SKILL.md missing YAML frontmatter (must start and end with ---)")]
    MissingFrontmatter,
    #[error("YAML parse error: {0}")]
    YamlParse(String),
    #[error("missing required field: {0}")]
    MissingField(String),
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn parse_full_skill_md() {
        let content = r#"---
name: commit-helper
description: Helps create well-structured git commits
license: MIT
tags:
  - git
  - workflow
allowed_tools:
  - bash
  - read_file
user_invocable: true
---
# Commit Helper

When the user asks to commit, follow these steps:
1. Run `git status` to see changes
2. Draft a commit message
3. Ask for confirmation
"#;

        let (meta, body) = parse_skill_md(content).unwrap();
        assert_eq!(meta.name, "commit-helper");
        assert_eq!(meta.description, "Helps create well-structured git commits");
        assert_eq!(meta.license, Some("MIT".to_string()));
        assert_eq!(meta.tags, vec!["git", "workflow"]);
        assert_eq!(
            meta.allowed_tools,
            Some(vec!["bash".to_string(), "read_file".to_string()])
        );
        assert_eq!(meta.user_invocable, Some(true));
        assert!(body.contains("# Commit Helper"));
        assert!(body.contains("Run `git status`"));
    }

    #[test]
    fn parse_minimal_skill_md() {
        let content = r#"---
name: simple
description: A simple skill
---
Just do the thing.
"#;
        let (meta, body) = parse_skill_md(content).unwrap();
        assert_eq!(meta.name, "simple");
        assert_eq!(meta.description, "A simple skill");
        assert_eq!(meta.tags, Vec::<String>::new());
        assert_eq!(meta.allowed_tools, None);
        assert_eq!(meta.user_invocable, None);
        assert_eq!(body, "Just do the thing.");
    }

    #[test]
    fn parse_missing_frontmatter_fails() {
        let content = "# No frontmatter\nJust text.";
        assert!(parse_skill_md(content).is_err());
    }

    #[test]
    fn parse_missing_name_fails() {
        let content = r#"---
description: No name field
---
Body."#;
        assert!(parse_skill_md(content).is_err());
    }

    #[test]
    fn parse_empty_name_fails() {
        let content = r#"---
name: ""
description: Empty name
---
Body."#;
        let err = parse_skill_md(content).unwrap_err();
        assert!(err.to_string().contains("name"));
    }
}

//! Skill registry for discovery and lookup.
//!
//! Scans directories for SKILL.md files, caches metadata,
//! and provides on-demand activation.

use crate::parser::{SkillMetadata, SkillParseError, parse_skill_md};
use std::collections::BTreeMap;
use std::path::{Path, PathBuf};
use thiserror::Error;

/// A loaded skill with its full content.
#[derive(Debug, Clone)]
pub struct LoadedSkill {
    pub meta: SkillMetadata,
    /// Markdown instructions (body after frontmatter).
    pub body: String,
    /// Skill directory (for relative file refs).
    pub root_dir: PathBuf,
}

/// Skill registry: scans directories, caches metadata, loads on demand.
pub struct SkillRegistry {
    skills: BTreeMap<String, LoadedSkill>,
}

impl SkillRegistry {
    /// Scan directories for SKILL.md files. Returns a registry of discovered skills.
    pub fn discover(dirs: &[PathBuf]) -> Result<Self, SkillError> {
        let mut skills = BTreeMap::new();

        for dir in dirs {
            if !dir.exists() {
                continue;
            }

            for entry in walkdir::WalkDir::new(dir)
                .into_iter()
                .filter_map(Result::ok)
                .filter(|e| e.file_type().is_file())
                .filter(|e| {
                    e.file_name()
                        .to_string_lossy()
                        .eq_ignore_ascii_case("SKILL.md")
                })
            {
                let path = entry.path();
                let content = std::fs::read_to_string(path).map_err(|e| SkillError::Io {
                    path: path.to_path_buf(),
                    source: e,
                })?;

                match parse_skill_md(&content) {
                    Ok((meta, body)) => {
                        let root_dir = path
                            .parent()
                            .unwrap_or_else(|| Path::new("."))
                            .to_path_buf();

                        let name = meta.name.clone();
                        skills.insert(
                            name,
                            LoadedSkill {
                                meta,
                                body,
                                root_dir,
                            },
                        );
                    }
                    Err(e) => {
                        tracing::warn!(
                            path = %path.display(),
                            error = %e,
                            "Skipping malformed skill"
                        );
                    }
                }
            }
        }

        Ok(Self { skills })
    }

    /// Number of discovered skills.
    pub fn count(&self) -> usize {
        self.skills.len()
    }

    /// Get skill metadata for system prompt injection.
    pub fn system_prompt_catalog(&self) -> String {
        if self.skills.is_empty() {
            return String::new();
        }

        let mut lines = vec!["Available skills:".to_string()];
        for skill in self.skills.values() {
            let invocable = if skill.meta.user_invocable == Some(true) {
                " [user-invocable]"
            } else {
                ""
            };
            lines.push(format!(
                "- {}: {}{}",
                skill.meta.name, skill.meta.description, invocable
            ));
        }
        lines.join("\n")
    }

    /// Load full skill content when activated.
    pub fn activate(&self, name: &str) -> Option<&LoadedSkill> {
        self.skills.get(name)
    }

    /// Get all skill names.
    pub fn skill_names(&self) -> Vec<String> {
        self.skills.keys().cloned().collect()
    }

    /// Get allowed tools for an active skill (if restricted).
    pub fn allowed_tools(&self, name: &str) -> Option<&[String]> {
        self.skills
            .get(name)
            .and_then(|s| s.meta.allowed_tools.as_deref())
    }
}

/// Errors from the skill system.
#[derive(Debug, Error)]
pub enum SkillError {
    #[error("IO error reading {path}: {source}")]
    Io {
        path: PathBuf,
        #[source]
        source: std::io::Error,
    },
    #[error("skill parse error: {0}")]
    Parse(#[from] SkillParseError),
}

#[cfg(test)]
mod tests {
    use super::*;
    use tempfile::TempDir;

    #[test]
    fn discovery_from_temp_dir() {
        let dir = TempDir::new().unwrap();

        let skill_dir = dir.path().join("my-skill");
        std::fs::create_dir_all(&skill_dir).unwrap();

        let skill_content = r#"---
name: test-skill
description: A test skill for unit tests
tags:
  - test
---
# Test Skill
This is the body.
"#;
        std::fs::write(skill_dir.join("SKILL.md"), skill_content).unwrap();

        let registry = SkillRegistry::discover(&[dir.path().to_path_buf()]).unwrap();
        assert_eq!(registry.count(), 1);

        let skill = registry.activate("test-skill").unwrap();
        assert_eq!(skill.meta.name, "test-skill");
        assert!(skill.body.contains("# Test Skill"));
        assert_eq!(skill.root_dir, skill_dir);
    }

    #[test]
    fn discovery_skips_malformed_skills() {
        let dir = TempDir::new().unwrap();

        let bad_dir = dir.path().join("bad-skill");
        std::fs::create_dir_all(&bad_dir).unwrap();
        std::fs::write(bad_dir.join("SKILL.md"), "no frontmatter here").unwrap();

        let good_dir = dir.path().join("good-skill");
        std::fs::create_dir_all(&good_dir).unwrap();
        std::fs::write(
            good_dir.join("SKILL.md"),
            "---\nname: good\ndescription: A good skill\n---\nGood body.",
        )
        .unwrap();

        let registry = SkillRegistry::discover(&[dir.path().to_path_buf()]).unwrap();
        assert_eq!(registry.count(), 1);
        assert!(registry.activate("good").is_some());
    }

    #[test]
    fn discovery_nonexistent_dir_is_ok() {
        let registry =
            SkillRegistry::discover(&[PathBuf::from("/nonexistent/path/12345")]).unwrap();
        assert_eq!(registry.count(), 0);
    }

    #[test]
    fn system_prompt_catalog_formatting() {
        let dir = TempDir::new().unwrap();

        let skill1_dir = dir.path().join("skill-a");
        std::fs::create_dir_all(&skill1_dir).unwrap();
        std::fs::write(
            skill1_dir.join("SKILL.md"),
            "---\nname: alpha\ndescription: Alpha skill\nuser_invocable: true\n---\nBody A.",
        )
        .unwrap();

        let skill2_dir = dir.path().join("skill-b");
        std::fs::create_dir_all(&skill2_dir).unwrap();
        std::fs::write(
            skill2_dir.join("SKILL.md"),
            "---\nname: beta\ndescription: Beta skill\n---\nBody B.",
        )
        .unwrap();

        let registry = SkillRegistry::discover(&[dir.path().to_path_buf()]).unwrap();
        let catalog = registry.system_prompt_catalog();

        assert!(catalog.contains("Available skills:"));
        assert!(catalog.contains("- alpha: Alpha skill [user-invocable]"));
        assert!(catalog.contains("- beta: Beta skill"));
    }

    #[test]
    fn allowed_tools_filtering() {
        let dir = TempDir::new().unwrap();
        let skill_dir = dir.path().join("restricted");
        std::fs::create_dir_all(&skill_dir).unwrap();
        std::fs::write(
            skill_dir.join("SKILL.md"),
            "---\nname: restricted\ndescription: Restricted skill\nallowed_tools:\n  - read_file\n  - grep\n---\nBody.",
        )
        .unwrap();

        let registry = SkillRegistry::discover(&[dir.path().to_path_buf()]).unwrap();
        let tools = registry.allowed_tools("restricted").unwrap();
        assert_eq!(tools, &["read_file", "grep"]);
    }

    #[test]
    fn skill_names_returns_all() {
        let dir = TempDir::new().unwrap();

        for name in &["aaa", "bbb", "ccc"] {
            let skill_dir = dir.path().join(name);
            std::fs::create_dir_all(&skill_dir).unwrap();
            std::fs::write(
                skill_dir.join("SKILL.md"),
                format!(
                    "---\nname: {}\ndescription: Skill {}\n---\nBody.",
                    name, name
                ),
            )
            .unwrap();
        }

        let registry = SkillRegistry::discover(&[dir.path().to_path_buf()]).unwrap();
        let mut names = registry.skill_names();
        names.sort();
        assert_eq!(names, vec!["aaa", "bbb", "ccc"]);
    }
}

//! MCP server connection management.
//!
//! Handles connecting to MCP servers via stdio transport
//! and discovering their available tools.

use crate::tool::McpTool;
use aios_protocol::tool::{ToolAnnotations, ToolDefinition};
use rmcp::ServiceExt;
use rmcp::model::Tool as McpToolDef;
use rmcp::service::{Peer, RoleClient};
use rmcp::transport::TokioChildProcess;
use serde::{Deserialize, Serialize};
use serde_json::Value;
use std::sync::Arc;
use thiserror::Error;
use tokio::process::Command;
use tokio::runtime::Handle;

/// Configuration for connecting to an MCP server.
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(deny_unknown_fields)]
pub struct McpServerConfig {
    pub name: String,
    pub transport: McpTransport,
}

/// Transport configuration for MCP connections.
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(tag = "type", rename_all = "snake_case")]
pub enum McpTransport {
    Stdio { command: String, args: Vec<String> },
}

/// A connected MCP client holding the running service.
pub struct McpConnection {
    pub server_name: String,
    pub tools: Vec<McpTool>,
    _service: Box<dyn std::any::Any + Send>,
}

/// Connect to an MCP server via stdio and return all its tools.
pub async fn connect_mcp_stdio(config: &McpServerConfig) -> Result<McpConnection, McpError> {
    let McpTransport::Stdio {
        ref command,
        ref args,
    } = config.transport;

    let mut cmd = Command::new(command);
    cmd.args(args);

    let transport =
        TokioChildProcess::new(cmd).map_err(|e| McpError::Connection(e.to_string()))?;

    let service = ()
        .serve(transport)
        .await
        .map_err(|e| McpError::Initialize(e.to_string()))?;

    let tools_result = service
        .list_tools(None)
        .await
        .map_err(|e| McpError::ListTools(e.to_string()))?;

    let runtime = Handle::current();
    let peer: Arc<Peer<RoleClient>> = Arc::new(service.peer().clone());

    let mcp_tools: Vec<McpTool> = tools_result
        .tools
        .iter()
        .map(|mcp_tool| {
            let (definition, mcp_tool_name) = mcp_tool_to_definition(&config.name, mcp_tool);
            McpTool::new(definition, peer.clone(), mcp_tool_name, runtime.clone())
        })
        .collect();

    Ok(McpConnection {
        server_name: config.name.clone(),
        tools: mcp_tools,
        _service: Box::new(service),
    })
}

/// Convert an MCP tool definition to a canonical ToolDefinition.
pub fn mcp_tool_to_definition(
    server_name: &str,
    mcp_tool: &McpToolDef,
) -> (ToolDefinition, String) {
    let mcp_name = mcp_tool.name.to_string();
    let canonical_name = format!("mcp_{}_{}", server_name, mcp_name);

    let annotations = mcp_tool.annotations.as_ref().map(|ann| ToolAnnotations {
        read_only: ann.read_only_hint.unwrap_or(false),
        destructive: ann.destructive_hint.unwrap_or(true),
        idempotent: ann.idempotent_hint.unwrap_or(false),
        open_world: ann.open_world_hint.unwrap_or(true),
        requires_confirmation: false,
    });

    let input_schema = Value::Object(mcp_tool.input_schema.as_ref().clone());

    let output_schema = mcp_tool
        .output_schema
        .as_ref()
        .map(|s| Value::Object(s.as_ref().clone()));

    let def = ToolDefinition {
        name: canonical_name,
        description: mcp_tool.description.as_deref().unwrap_or("").to_string(),
        input_schema,
        title: mcp_tool
            .title
            .clone()
            .or_else(|| mcp_tool.annotations.as_ref().and_then(|a| a.title.clone())),
        output_schema,
        annotations,
        category: Some("mcp".into()),
        tags: vec!["mcp".into(), server_name.into()],
        timeout_secs: Some(60),
    };

    (def, mcp_name)
}

/// Errors from MCP connection management.
#[derive(Debug, Error)]
pub enum McpError {
    #[error("MCP connection failed: {0}")]
    Connection(String),
    #[error("MCP initialization failed: {0}")]
    Initialize(String),
    #[error("MCP tools/list failed: {0}")]
    ListTools(String),
}

#[cfg(test)]
mod tests {
    use super::*;
    use rmcp::model::{Tool as McpToolDef, ToolAnnotations as McpAnnotations};
    use serde_json::json;
    use std::sync::Arc;

    #[test]
    fn mcp_tool_to_definition_conversion() {
        let mcp_tool = McpToolDef {
            name: "read_file".into(),
            title: Some("Read File".to_string()),
            description: Some("Reads a file from disk".into()),
            input_schema: Arc::new(
                serde_json::from_value(json!({
                    "type": "object",
                    "properties": {
                        "path": { "type": "string" }
                    },
                    "required": ["path"]
                }))
                .unwrap(),
            ),
            output_schema: None,
            annotations: Some(McpAnnotations {
                title: None,
                read_only_hint: Some(true),
                destructive_hint: Some(false),
                idempotent_hint: Some(true),
                open_world_hint: Some(false),
            }),
            execution: None,
            icons: None,
            meta: None,
        };

        let (def, original_name) = mcp_tool_to_definition("test-server", &mcp_tool);

        assert_eq!(def.name, "mcp_test-server_read_file");
        assert_eq!(original_name, "read_file");
        assert_eq!(def.description, "Reads a file from disk");
        assert_eq!(def.title, Some("Read File".to_string()));
        assert_eq!(def.category, Some("mcp".to_string()));
        assert!(def.tags.contains(&"mcp".to_string()));
        assert!(def.tags.contains(&"test-server".to_string()));

        let ann = def.annotations.unwrap();
        assert!(ann.read_only);
        assert!(!ann.destructive);
        assert!(ann.idempotent);
        assert!(!ann.open_world);
    }

    #[test]
    fn mcp_tool_without_annotations() {
        let mcp_tool = McpToolDef {
            name: "simple".into(),
            title: None,
            description: Some("A simple tool".into()),
            input_schema: Arc::new(serde_json::from_value(json!({"type": "object"})).unwrap()),
            output_schema: None,
            annotations: None,
            execution: None,
            icons: None,
            meta: None,
        };

        let (def, _) = mcp_tool_to_definition("srv", &mcp_tool);
        assert_eq!(def.name, "mcp_srv_simple");
        assert!(def.annotations.is_none());
        assert!(def.title.is_none());
    }
}

//! McpTool — wraps a single MCP server tool as a canonical Tool.

use aios_protocol::tool::{
    Tool, ToolCall, ToolContent, ToolContext, ToolDefinition, ToolError, ToolResult,
};
use rmcp::model::{CallToolRequestParams, RawContent};
use rmcp::service::{Peer, RoleClient};
use serde_json::json;
use std::borrow::Cow;
use std::sync::Arc;
use tokio::runtime::Handle;

/// Bridge: wraps a single MCP tool into the canonical Tool trait.
pub struct McpTool {
    definition: ToolDefinition,
    peer: Arc<Peer<RoleClient>>,
    mcp_tool_name: String,
    runtime: Handle,
}

impl McpTool {
    /// Create a new MCP tool bridge.
    pub fn new(
        definition: ToolDefinition,
        peer: Arc<Peer<RoleClient>>,
        mcp_tool_name: String,
        runtime: Handle,
    ) -> Self {
        Self {
            definition,
            peer,
            mcp_tool_name,
            runtime,
        }
    }
}

impl Tool for McpTool {
    fn definition(&self) -> ToolDefinition {
        self.definition.clone()
    }

    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, ToolError> {
        let arguments = call.input.as_object().cloned();

        let params = CallToolRequestParams {
            meta: None,
            name: Cow::Owned(self.mcp_tool_name.clone()),
            arguments,
            task: None,
        };

        let peer = self.peer.clone();
        let mcp_result = self
            .runtime
            .block_on(async move { peer.call_tool(params).await })
            .map_err(|e| ToolError::ExecutionFailed {
                tool_name: call.tool_name.clone(),
                message: format!("MCP call_tool failed: {e}"),
            })?;

        // Convert MCP content to canonical ToolContent
        let content: Vec<ToolContent> = mcp_result
            .content
            .iter()
            .filter_map(|c| match &c.raw {
                RawContent::Text(text) => Some(ToolContent::Text {
                    text: text.text.clone(),
                }),
                RawContent::Image(img) => Some(ToolContent::Image {
                    data: img.data.clone(),
                    mime_type: img.mime_type.clone(),
                }),
                _ => None,
            })
            .collect();

        // Build JSON output for backward compat
        let output = if let Some(structured) = &mcp_result.structured_content {
            structured.clone()
        } else {
            let texts: Vec<String> = mcp_result
                .content
                .iter()
                .filter_map(|c| c.as_text().map(|t| t.text.clone()))
                .collect();
            json!({ "text": texts.join("\n") })
        };

        Ok(ToolResult {
            call_id: call.call_id.clone(),
            tool_name: call.tool_name.clone(),
            output,
            content: if content.is_empty() {
                None
            } else {
                Some(content)
            },
            is_error: mcp_result.is_error.unwrap_or(false),
        })
    }
}

