  1→//! McpTool — wraps a single MCP server tool as a canonical Tool.
  2→
  3→use aios_protocol::tool::{
  4→    Tool, ToolCall, ToolContent, ToolContext, ToolDefinition, ToolError, ToolResult,
  5→};
  6→use rmcp::model::{CallToolRequestParams, RawContent};
  7→use rmcp::service::{Peer, RoleClient};
  8→use serde_json::json;
  9→use std::borrow::Cow;
 10→use std::sync::Arc;
 11→use tokio::runtime::Handle;
 12→
 13→/// Bridge: wraps a single MCP tool into the canonical Tool trait.
 14→pub struct McpTool {
 15→    definition: ToolDefinition,
 16→    peer: Arc<Peer<RoleClient>>,
 17→    mcp_tool_name: String,
 18→    runtime: Handle,
 19→}
 20→
 21→impl McpTool {
 22→    /// Create a new MCP tool bridge.
 23→    pub fn new(
 24→        definition: ToolDefinition,
 25→        peer: Arc<Peer<RoleClient>>,
 26→        mcp_tool_name: String,
 27→        runtime: Handle,
 28→    ) -> Self {
 29→        Self {
 30→            definition,
 31→            peer,
 32→            mcp_tool_name,
 33→            runtime,
 34→        }
 35→    }
 36→}
 37→
 38→impl Tool for McpTool {
 39→    fn definition(&self) -> ToolDefinition {
 40→        self.definition.clone()
 41→    }
 42→
 43→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, ToolError> {
 44→        let arguments = call.input.as_object().cloned();
 45→
 46→        let params = CallToolRequestParams {
 47→            meta: None,
 48→            name: Cow::Owned(self.mcp_tool_name.clone()),
 49→            arguments,
 50→            task: None,
 51→        };
 52→
 53→        let peer = self.peer.clone();
 54→        let mcp_result = self
 55→            .runtime
 56→            .block_on(async move { peer.call_tool(params).await })
 57→            .map_err(|e| ToolError::ExecutionFailed {
 58→                tool_name: call.tool_name.clone(),
 59→                message: format!("MCP call_tool failed: {e}"),
 60→            })?;
 61→
 62→        // Convert MCP content to canonical ToolContent
 63→        let content: Vec<ToolContent> = mcp_result
 64→            .content
 65→            .iter()
 66→            .filter_map(|c| match &c.raw {
 67→                RawContent::Text(text) => Some(ToolContent::Text {
 68→                    text: text.text.clone(),
 69→                }),
 70→                RawContent::Image(img) => Some(ToolContent::Image {
 71→                    data: img.data.clone(),
 72→                    mime_type: img.mime_type.clone(),
 73→                }),
 74→                _ => None,
 75→            })
 76→            .collect();
 77→
 78→        // Build JSON output for backward compat
 79→        let output = if let Some(structured) = &mcp_result.structured_content {
 80→            structured.clone()
 81→        } else {
 82→            let texts: Vec<String> = mcp_result
 83→                .content
 84→                .iter()
 85→                .filter_map(|c| c.as_text().map(|t| t.text.clone()))
 86→                .collect();
 87→            json!({ "text": texts.join("\n") })
 88→        };
 89→
 90→        Ok(ToolResult {
 91→            call_id: call.call_id.clone(),
 92→            tool_name: call.tool_name.clone(),
 93→            output,
 94→            content: if content.is_empty() {
 95→                None
 96→            } else {
 97→                Some(content)
 98→            },
 99→            is_error: mcp_result.is_error.unwrap_or(false),
100→        })
101→    }
102→}
103→

